// ==============================
// Validation Utilities
// ==============================
class ValidationUtils {

  static isValidEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  static isRequired(value) {
    return value !== null && value !== undefined && value !== '';
  }

  static isValidLength(str, min = 0, max = 255) {
    if (typeof str !== 'string') return false;
    return str.length >= min && str.length <= max;
  }

  static validateFields(data, rules) {
    const errors = [];

    for (const [field, fieldRules] of Object.entries(rules)) {
      const value = data[field];

      for (const rule of fieldRules) {
        switch (rule.type) {

          case 'required':
            if (!this.isRequired(value)) {
              errors.push({
                field,
                message: rule.message || `${field} is required`,
                type: 'required'
              });
            }
            break;

          case 'email':
            if (value && !this.isValidEmail(value)) {
              errors.push({
                field,
                message: rule.message || `${field} must be valid`,
                type: 'email'
              });
            }
            break;

          case 'length':
            if (value && !this.isValidLength(value, rule.min, rule.max)) {
              errors.push({
                field,
                message: rule.message || `${field} must be ${rule.min}-${rule.max} chars`,
                type: 'length'
              });
            }
            break;

        }
      }
    }

    return {
      isValid: errors.length === 0,
      errors
    };
  }
}


// ==============================
// Main Execution (Bulk Mode)
// ==============================

// Expecting:
// {
//   data: [ {...}, {...} ],
//   rules: { ... }
// }

const input = $input.first().json;
const { data, rules } = input;


// ❌ Invalid input guard
if (!Array.isArray(data) || !rules) {
  return [{
    json: {
      success: false,
      message: 'Invalid input: data must be array & rules required'
    }
  }];
}


// ==============================
// Process each lead
// ==============================
return data.map((item, index) => {

  // 🔹 Normalize data
  const clean = {
    name: item.name?.trim() || null,
    email: item.email?.toLowerCase()?.trim() || null,
    message: item.message?.trim() || null
  };

  // 🔹 Validate
  const result = ValidationUtils.validateFields(clean, rules);

  return {
    json: {
      index,                     // helps tracking
      ...clean,                  // cleaned data
      success: result.isValid,   // main flag
      errors: result.errors,     // structured errors
      error_count: result.errors.length,
      timestamp: new Date().toISOString()
    }
  };
});
